const payload = $json;
const timestamp = new Date().toISOString();
const dateStr = new Date().toLocaleString('es-CO');

let output = `
в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—
в•‘     NEXUSRECOVER вҖ” HOSPITALITY NOTIFICATION                    в•‘
в•‘                 IRROPS Decision Support System                  в•‘
в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ

вҸ° Timestamp: ${dateStr}
ID: ${payload.scenario_id || 'unknown'}

в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ
DISRUPTION SUMMARY
в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ

рҹӣ« Hub Airport:           ${payload.disruption_summary?.hub_airport || 'YYZ'}
вҡ пёҸ  Event:                ${payload.disruption_summary?.event || 'Unknown'}

рҹ“Ҡ Impact Summary:
   вҖў Diverted flights:    ${payload.disruption_summary?.total_diverted_flights || 0}
   вҖў PAX diverted:        ${payload.disruption_summary?.total_pax_diverted || 0}
   вҖў PAX stranded at hub: ${payload.disruption_summary?.total_pax_stranded_at_hub || 0}

   Stranded breakdown:
   вҖў Business class:      ${payload.disruption_summary?.pax_breakdown_stranded?.business || 0}
   вҖў Economy class:       ${payload.disruption_summary?.pax_breakdown_stranded?.economy || 0}

в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ
ALTERNATE AIRPORT OPERATIONS
в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ
`;

const altOps = payload.alternate_airport_ops || [];
const activeAlts = altOps.filter(a => a.status === 'ACTIVE');

if (activeAlts.length > 0) {
  for (let i = 0; i < activeAlts.length; i++) {
    const alt = activeAlts[i];
    output += `
в”Ңв”Җ ALTERNATE AIRPORT ${i + 1}: ${alt.iata} в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ
в”Ӯ
в”Ӯ  Name:                    ${alt.name}
в”Ӯ  Status:                  ${alt.status}
в”Ӯ  
в”Ӯ  вңҲпёҸ  Incoming Flights:
`;
    if (alt.incoming_flights && alt.incoming_flights.length > 0) {
      for (const flight of alt.incoming_flights) {
        output += `в”Ӯ    вҖў ${flight.flight_id} from ${flight.origin} (${flight.aircraft}) - ETA ${flight.eta}\n`;
      }
    }
    output += `в”Ӯ  
в”Ӯ  рҹ‘Ҙ Passenger Summary:
в”Ӯ    вҖў Total incoming:      ${alt.total_pax_incoming}
в”Ӯ    вҖў Business class:      ${alt.pax_breakdown?.business || 0}
в”Ӯ    вҖў Economy class:       ${alt.pax_breakdown?.economy || 0}
в”Ӯ  
в”Ӯ  рҹҡҢ Ground Transport:
в”Ӯ    вҖў Provider:            ${alt.ground_transport?.provider_contact || 'TBD'}
в”Ӯ    вҖў Vehicles required:   ${alt.ground_transport?.vehicles_required || 0}
в”Ӯ    вҖў Pickup location:     ${alt.ground_transport?.pickup_airport || alt.iata}
в”Ӯ    вҖў Drop-off:            ${alt.ground_transport?.drop_off || 'YYZ'}
в”Ӯ    вҖў Transfer time:       ${alt.ground_transport?.estimated_transfer_min || 0} minutes
в”Ӯ    вҖў Cost per PAX:        $${alt.ground_transport?.cost_per_pax_usd || 0}
в”Ӯ    вҖў Total transport:     $${(alt.ground_transport?.total_transport_cost_usd || 0).toLocaleString('en-US')}
в”Ӯ    вҖў Priority boarding:   ${alt.ground_transport?.priority_boarding || 'Standard'}
в”Ӯ  
в”Ӯ  рҹ“Ӣ On-Site Requirements:
`;
    if (alt.on_site_requirements) {
      for (const req of alt.on_site_requirements) {
        output += `в”Ӯ    вң“ ${req}\n`;
      }
    }
    output += `в”Ӯ
в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ
`;
  }
} else {
  output += `\n  (No active alternate airports)\n`;
}

output += `
в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ
STRANDED PASSENGERS AT HUB (${payload.stranded_pax_at_hub?.total_pax || 0} PAX)
в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ
`;

const stranded = payload.stranded_pax_at_hub || {};
if (stranded.total_pax > 0) {
  output += `
рҹҸЁ Hotel Requirements:
   вҖў Total rooms needed:     ${stranded.hotel_rooms_required || 0} rooms
   вҖў Hotel standard:         ${stranded.hotel_type_required || '3-4 star'}
   вҖў Meals per PAX:          $${stranded.meal_vouchers?.value_per_pax_usd || 0}
   вҖў Total meal vouchers:    ${stranded.meal_vouchers?.count || 0} Г— $${stranded.meal_vouchers?.value_per_pax_usd || 0}

рҹ‘Ҙ Passenger Groups:
`;
  if (stranded.groups && stranded.groups.length > 0) {
    for (const grp of stranded.groups) {
      output += `   вҖў ${grp.group_id}: ${grp.count} ${grp.tier.toUpperCase()} PAX from ${grp.origin} вҶ’ ${grp.missed_destination}\n`;
      output += `     Cost: $${(grp.total_stranding_cost_usd || 0).toLocaleString('en-US')}\n`;
    }
  }
} else {
  output += `\n  (No stranded passengers - all connections made)\n`;
}

output += `
в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ
YYZ HUB REQUIREMENTS
в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ
`;

const yyzReqs = payload.yyz_hub_requirements || {};
output += `
рҹҺ« Lounge & Services:
   вҖў Lounge activation:      ${yyzReqs.lounge_activation ? 'YES' : 'NO'}`;
if (yyzReqs.lounge_activation) {
  output += ` (${yyzReqs.lounge_pax_count || 0} Business PAX)`;
}
output += `
   вҖў Service desks needed:   ${yyzReqs.customer_service_desks_needed || 0}

рҹ“Ӣ Rebooking Priority:
`;
if (yyzReqs.rebooking_priority) {
  for (const priority of yyzReqs.rebooking_priority) {
    output += `   1пёҸвғЈ  ${priority}\n`;
  }
}
output += `
рҹ“ў Passenger Announcement:
   "${yyzReqs.announcement_script || 'N/A'}"\n`;

output += `
в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ
COST SUMMARY
в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ
`;

const costs = payload.cost_summary || {};
output += `
рҹ’° Hospitality Costs:
   вҖў Ground transport:       $${(costs.ground_transport_total_usd || 0).toLocaleString('en-US')}
   вҖў Stranded PAX (hotels):  $${(costs.stranded_pax_total_cost_usd || 0).toLocaleString('en-US')}
   в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
   вҖў TOTAL:                  $${((costs.ground_transport_total_usd || 0) + (costs.stranded_pax_total_cost_usd || 0)).toLocaleString('en-US')}

`;

output += `в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—
в•‘ End of Hospitality Notification                                в•‘
в•‘ Generated by: ${payload.issued_by || 'NexusRecover'}${' '.repeat(30 - (payload.issued_by || 'NexusRecover').length)}в•‘
в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ
`;

return { formattedText: output };
